class Solution:
    def minimizeArrayValue(self, nums):
        # Binary search the answer: feasibility check simulates the leftward flow.
        def feasible(cap):
            carry = 0
            for v in nums:
                if v <= cap:
                    carry += cap - v  # capacity to absorb from the right
                else:
                    need = v - cap
                    if need > carry:
                        return False
                    carry -= need
            return True
        lo, hi = 0, max(nums)
        while lo < hi:
            mid = (lo + hi) // 2
            if feasible(mid):
                hi = mid
            else:
                lo = mid + 1
        return lo

