class Solution:
    def minimizeArrayValue(self, nums):
        total = 0
        ans = 0
        for i, v in enumerate(nums):
            total += v
            ceil_avg = (total + i) // (i + 1)
            if ceil_avg > ans:
                ans = ceil_avg
        return ans

