var minimizeArrayValue = function(nums) {
    let total = 0n;
    let ans = 0n;
    for (let i = 0; i < nums.length; i++) {
        total += BigInt(nums[i]);
        const len = BigInt(i + 1);
        const ceilAvg = (total + len - 1n) / len;
        if (ceilAvg > ans) ans = ceilAvg;
    }
    return Number(ans);
};
